def solve(*args):
    if not args:
        return None

    # Assuming args[0] is the project and args[1] is the user
    project, user = args[0], args[1]

    # Check if the user has permission to access project attachments
    if user.has_permission('view_attachments', project):
        return project.get_attachments()
    else:
        return None
